-- Generated by SQL Adventure Builder. Any changes will be overwritten.
-- See at the end of the file for more information.

CREATE TABLE brokers (
    id INT,
    name VARCHAR,
    part VARCHAR,
    extra_part_1 VARCHAR,
    extra_part_2 VARCHAR,
    compromised INT DEFAULT 0,
    hash BIGINT DEFAULT 0
);

CREATE TABLE flora_colossi (
    id BIGINT PRIMARY KEY,
    name VARCHAR,
    title VARCHAR,
    world VARCHAR,
    hash BIGINT DEFAULT 0
);

CREATE TABLE lineage (
    descendant_id BIGINT,
    ancestor_id BIGINT,
    relation VARCHAR,
    hash BIGINT DEFAULT 0
);

CREATE PROPERTY GRAPH groot_lineage_graph
VERTEX TABLES (
    flora_colossi LABEL Colossus
)
EDGE TABLES (
    lineage
      SOURCE KEY (descendant_id) REFERENCES flora_colossi (id)
      DESTINATION KEY (ancestor_id) REFERENCES flora_colossi (id)
      LABEL DESCENDS_FROM
);

CREATE TABLE trades (
    source_id INT, 
    target_id INT, 
    cost INT,
    hash BIGINT DEFAULT 0
);

CREATE PROPERTY GRAPH trade_graph
VERTEX TABLES (
    brokers LABEL Broker
)
EDGE TABLES (
    trades SOURCE KEY (source_id) REFERENCES brokers(id)
           DESTINATION KEY (target_id) REFERENCES brokers(id)
           LABEL TRADES_WITH
);


DROP TABLE IF EXISTS sqlab_msg;
CREATE TABLE sqlab_msg (
  msg TEXT NOT NULL
);

DROP TABLE IF EXISTS sqlab_metadata;
CREATE TABLE sqlab_metadata (
  name VARCHAR(64) NOT NULL,
  value JSON NOT NULL,
  PRIMARY KEY (name)
);


CREATE OR REPLACE MACRO nn(x) AS coalesce(x, 0);

CREATE OR REPLACE MACRO string_hash(x) AS (
    CAST(
        regexp_replace(
            sha256(CAST(x AS VARCHAR))::VARCHAR,
            '[a-f]',
            '',
            'g'
        )[:12]
    AS BIGINT)
);

CREATE OR REPLACE MACRO encrypt(msg, token) AS
  sha256(CAST(token AS VARCHAR))::VARCHAR || to_base64(encode(msg));

CREATE OR REPLACE MACRO decrypt(token) AS TABLE
    SELECT msg AS msg
    FROM (
        SELECT 1 AS priority,
               decode(from_base64(substr(msg, 65))) AS msg
        FROM sqlab_msg
        WHERE substr(msg, 1, 64) = sha256(CAST(token AS VARCHAR))::VARCHAR
        UNION ALL
        SELECT 2 AS priority,
               '🔴 No specific message is planned for this token. Possible reasons:
1. Copy-paste accident (double-click on the token to facilitate selection).
2. Formula for calculating the token not updated.
3. (0) still present, or replaced by the wrong value.
4. New logical error. Congratulations on your creativity! Now read the statement carefully and, if the symptoms persist, ask your teacher.' AS msg
    ) sub
    ORDER BY priority
    LIMIT 1;


